export interface CSVParseOptions {
  delimiter?: string;
  quoteChar?: string;
  lineSeparator?: string;
}

export interface CSVParseError {
  row: number;
  message: string;
}

export interface CSVResult<T = Record<string, any>> {
  rows: T[];
  headers: string[];
  errors: CSVParseError[];
  filter(predicate: (row: T, index: number) => boolean): T[];
  sum(column: string): number;
  average(column: string): number;
  count(): number;
  groupBy(column: string): Map<any, T[]>;
}

function coerceValue(value: string): any {
  if (value === "") {
    return null;
  }
  const trimmed = value;
  if (/^null$/i.test(trimmed)) {
    return null;
  }
  if (/^true$/i.test(trimmed)) {
    return true;
  }
  if (/^false$/i.test(trimmed)) {
    return false;
  }
  if (/^[+-]?\d+$/.test(trimmed)) {
    const intVal = Number(trimmed);
    if (Number.isFinite(intVal)) {
      return intVal;
    }
  }
  if (/^[+-]?(\d+\.\d+|\d+\.|\.\d+)$/.test(trimmed)) {
    const floatVal = Number(trimmed);
    if (Number.isFinite(floatVal)) {
      return floatVal;
    }
  }
  return value;
}

function parseRows(input: string, options: CSVParseOptions, errors: CSVParseError[]): string[][] {
  const delimiter = options.delimiter ?? ",";
  const quoteChar = options.quoteChar ?? '"';
  const lineSep = options.lineSeparator;

  const rows: string[][] = [];
  let currentRow: string[] = [];
  let currentField = "";
  let inQuotes = false;

  const endField = () => {
    currentRow.push(currentField);
    currentField = "";
  };

  const endRow = () => {
    endField();
    rows.push(currentRow);
    currentRow = [];
  };

  let i = 0;
  while (i < input.length) {
    const char = input[i];

    if (char === quoteChar) {
      if (inQuotes) {
        const nextChar = input[i + 1];
        if (nextChar === quoteChar) {
          currentField += quoteChar;
          i += 1;
        } else {
          inQuotes = false;
        }
      } else if (currentField.length === 0) {
        inQuotes = true;
      } else {
        currentField += char;
      }
      i += 1;
      continue;
    }

    if (!inQuotes) {
      if (lineSep) {
        if (input.startsWith(lineSep, i)) {
          endRow();
          i += lineSep.length;
          continue;
        }
      } else if (char === "\n" || char === "\r") {
        if (char === "\r" && input[i + 1] === "\n") {
          i += 1;
        }
        endRow();
        i += 1;
        continue;
      }

      if (char === delimiter) {
        endField();
        i += 1;
        continue;
      }
    }

    currentField += char;
    i += 1;
  }

  if (inQuotes) {
    errors.push({ row: rows.length + 1, message: "Unclosed quote" });
  }

  if (currentField.length > 0 || currentRow.length > 0 || input.endsWith(delimiter)) {
    endRow();
  }

  return rows;
}

export function parseCSV(input: string, options: CSVParseOptions = {}): CSVResult {
  const errors: CSVParseError[] = [];
  const rows = parseRows(input, options, errors);

  if (rows.length === 0) {
    return {
      rows: [],
      headers: [],
      errors,
      filter: () => [],
      sum: () => 0,
      average: () => 0,
      count: () => 0,
      groupBy: () => new Map(),
    };
  }

  const headers = rows[0].map((header) => header);
  const dataRows = rows.slice(1);

  const parsedRows = dataRows.map((row, index) => {
    if (row.length !== headers.length) {
      errors.push({
        row: index + 2,
        message: `Expected ${headers.length} fields, got ${row.length}`,
      });
    }
    const record: Record<string, any> = {};
    headers.forEach((header, i) => {
      const value = row[i] ?? "";
      record[header] = coerceValue(value);
    });
    return record;
  });

  const result: CSVResult = {
    rows: parsedRows,
    headers,
    errors,
    filter: (predicate) => parsedRows.filter(predicate),
    sum: (column) => {
      return parsedRows.reduce((total, row) => {
        const value = row[column];
        if (typeof value === "number" && Number.isFinite(value)) {
          return total + value;
        }
        return total;
      }, 0);
    },
    average: (column) => {
      let total = 0;
      let count = 0;
      parsedRows.forEach((row) => {
        const value = row[column];
        if (typeof value === "number" && Number.isFinite(value)) {
          total += value;
          count += 1;
        }
      });
      return count === 0 ? 0 : total / count;
    },
    count: () => parsedRows.length,
    groupBy: (column) => {
      const map = new Map<any, Record<string, any>[]>();
      parsedRows.forEach((row) => {
        const key = row[column];
        const group = map.get(key);
        if (group) {
          group.push(row);
        } else {
          map.set(key, [row]);
        }
      });
      return map;
    },
  };

  return result;
}

import { parseCSV } from "./csv-parser";

function assert(condition: any, message: string) {
  if (!condition) {
    throw new Error(message);
  }
}

// Basic parsing
{
  const result = parseCSV("a,b\n1,2\n3,4");
  assert(result.headers.join(",") === "a,b", "Headers should parse correctly");
  assert(result.rows.length === 2, "Should parse two rows");
  assert(result.rows[0].a === 1 && result.rows[0].b === 2, "Row values should coerce to numbers");
}

// Quoted fields with commas
{
  const result = parseCSV('name,desc\n"hello, world",test');
  assert(result.rows[0].name === "hello, world", "Quoted field with comma should parse");
}

// Escaped quotes
{
  const result = parseCSV('a\n"he said ""hi"""');
  assert(result.rows[0].a === 'he said "hi"', "Escaped quotes should parse correctly");
}

// Custom delimiters
{
  const result = parseCSV("a;b|1;2", { delimiter: ";", lineSeparator: "|" });
  assert(result.rows.length === 1, "Custom delimiter should parse one row");
  assert(result.rows[0].a === 1 && result.rows[0].b === 2, "Custom delimiter values should parse");
}

// Type coercion
{
  const result = parseCSV("i,f,b,n,e,s\n1,1.5,TRUE,null,,text");
  const row = result.rows[0];
  assert(row.i === 1, "Integer should coerce");
  assert(row.f === 1.5, "Float should coerce");
  assert(row.b === true, "Boolean should coerce");
  assert(row.n === null, "Null should coerce");
  assert(row.e === null, "Empty string should coerce to null");
  assert(row.s === "text", "String should remain string");
}

// Malformed row error collection
{
  const result = parseCSV("a,b\n1,2,3\n4");
  assert(result.errors.length === 2, "Should collect two errors for malformed rows");
  assert(result.errors[0].row === 2, "First error should reference row 2");
  assert(result.errors[1].row === 3, "Second error should reference row 3");
  assert(result.rows[1].b === null, "Missing field should coerce to null");
}

// Filter functionality
{
  const result = parseCSV("a,b\n1,2\n3,4\n5,6");
  const filtered = result.filter((row) => row.a > 2);
  assert(filtered.length === 2, "Filter should return matching rows");
}

// Aggregation methods
{
  const result = parseCSV("group,value\nA,10\nA,20\nB,5");
  assert(result.sum("value") === 35, "Sum should aggregate numeric values");
  assert(result.average("value") === 35 / 3, "Average should compute mean");
  assert(result.count() === 3, "Count should return total rows");
  const grouped = result.groupBy("group");
  assert(grouped.get("A")?.length === 2, "GroupBy should group rows");
  assert(grouped.get("B")?.length === 1, "GroupBy should group rows");
}

// Edge cases
{
  const empty = parseCSV("");
  assert(empty.headers.length === 0 && empty.rows.length === 0, "Empty input should return empty result");

  const singleColumn = parseCSV("a\n1\n2");
  assert(singleColumn.headers.length === 1, "Single column should parse header");
  assert(singleColumn.rows.length === 2, "Single column should parse rows");

  const headerOnly = parseCSV("a,b");
  assert(headerOnly.rows.length === 0, "Header-only input should have no rows");

  const largeField = "x".repeat(10000);
  const largeResult = parseCSV(`a\n"${largeField}"`);
  assert(largeResult.rows[0].a === largeField, "Large field should parse correctly");
}

console.log("All tests passed");

