      errors,
      filter: () => [],
      sum: () => 0,
      average: () => 0,
      count: () => 0,
      groupBy: () => new Map(),
    };
  }

  const headers = rows[0].map((header) => header);
  const dataRows = rows.slice(1);

  const parsedRows = dataRows.map((row, index) => {
    if (row.length !== headers.length) {
      errors.push({
        row: index + 2,
        message: `Expected ${headers.length} fields, got ${row.length}`,
      });
    }
    const record: Record<string, any> = {};
    headers.forEach((header, i) => {
      const value = row[i] ?? "";
      record[header] = coerceValue(value);
    });
    return record;
  });

  const result: CSVResult = {
    rows: parsedRows,
    headers,
    errors,
    filter: (predicate) => parsedRows.filter(predicate),
    sum: (column) => {
      return parsedRows.reduce((total, row) => {
        const value = row[column];
        if (typeof value === "number" && Number.isFinite(value)) {
          return total + value;
        }
        return total;
      }, 0);
    },
    average: (column) => {
      let total = 0;
      let count = 0;
      parsedRows.forEach((row) => {
        const value = row[column];
        if (typeof value === "number" && Number.isFinite(value)) {
          total += value;
          count += 1;
        }
      });
      return count === 0 ? 0 : total / count;
    },
    count: () => parsedRows.length,
    groupBy: (column) => {
      const map = new Map<any, Record<string, any>[]>();
      parsedRows.forEach((row) => {
        const key = row[column];
        const group = map.get(key);
        if (group) {
          group.push(row);
        } else {
          map.set(key, [row]);
        }
      });
      return map;
    },
  };

  return result;
}
